```javascript
function solve(nums, k) {
    nums.sort((a, b) => a - b);
    let n = nums.length;
    let maxLen = 1;

    for (let i = 0; i < n; i++) {
        let target = nums[i] * k;
        let low = i;
        let high = n - 1;
        let bestJ = i - 1;

        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                bestJ = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        if (bestJ >= i) {
            let currentLen = bestJ - i + 1;
            if (currentLen > maxLen) {
                maxLen = currentLen;
            }
        }
    }

    return n - maxLen;
}
